-- =============================================================================
-- Medicine seed data: 4 flashcard sets for medical students
-- Sets: Skeletal System (60), Muscular System (50), Drug Classes (50), Medical Terminology (60)
-- =============================================================================

-- ─────────────────────────────────────────────────────────────────────────────
-- 1. Anatomia — Uklad kostny (60 cards)
-- ─────────────────────────────────────────────────────────────────────────────
DO $$
DECLARE v_set_id integer;
BEGIN

VALUES ('00000000-0000-0000-0000-000000000001', 'Anatomia — Układ kostny', 'Najważniejsze kości ludzkiego ciała: nazwy łacińskie, lokalizacja, funkcje', '{"medicine","anatomy","bones","medical"}', true, now(), now(), now())
RETURNING id INTO v_set_id;


END $$;

