INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Os frontale', 'Kość czołowa — tworzy przednią część sklepienia czaszki i górną ścianę oczodołu. Zawiera zatokę czołową (sinus frontalis).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os parietale', 'Kość ciemieniowa — parzysta kość sklepienia czaszki. Dwie kości ciemieniowe łączą się w szwie strzałkowym (sutura sagittalis).', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os occipitale', 'Kość potyliczna — tylna część czaszki. Posiada otwór wielki (foramen magnum), przez który rdzeń kręgowy łączy się z mózgiem.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os temporale', 'Kość skroniowa — parzysta kość bocznej części czaszki. Zawiera narząd słuchu i równowagi, wyrostek sutkowaty i dół żuchwowy.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os sphenoidale', 'Kość klinowa — leży w środkowej części podstawy czaszki. Posiada siodło tureckie (sella turcica), w którym znajduje się przysadka mózgowa.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os ethmoidale', 'Kość sitowa — drobna kość podstawy czaszki między oczodołami. Tworzy blaszki sitowe i małżowinę nosową górną. Uczestniczy w budowie jamy nosowej.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os nasale', 'Kość nosowa — parzysta, mała kość tworząca grzbiet nosa. Łączy się z kością czołową i wyrostkiem czołowym szczęki.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os zygomaticum', 'Kość jarzmowa — tworzy wyniosłość policzka i boczną ścianę oczodołu. Łączy się z kością skroniową tworząc łuk jarzmowy.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Maxilla', 'Szczęka — największa nieruchoma kość twarzy. Tworzy dno oczodołu, boczną ścianę jamy nosowej. Zawiera zatokę szczękową i zęby górne.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Mandibula', 'Żuchwa — jedyna ruchoma kość czaszki. Posiada trzon, gałęzie, wyrostek kłykciowy (staw skroniowo-żuchwowy) i wyrostek dziobiasty.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os lacrimale', 'Kość łzowa — najmniejsza kość twarzy, leży w przyśrodkowej ścianie oczodołu. Zawiera dół woreczka łzowego.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vomer', 'Lemiesz — nieparzysty element tylno-dolnej części przegrody nosowej. Łączy się z kością klinową i podniebieniem twardym.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os palatinum', 'Kość podniebienna — parzysta kość tworzącą tylną część podniebienia twardego i boczną ścianę jamy nosowej.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os hyoideum', 'Kość gnykowa — jedyna kość nie połączona stawowo z innymi kośćmi. Leży w szyi powyżej chrząstki tarczowatej krtani. Miejsce przyczepów mięśni języka.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Concha nasalis inferior', 'Małżowina nosowa dolna — samodzielna kość jamy nosowej. Zwiększa powierzchnię błony śluzowej, ogrzewa i nawilża wdychane powietrze.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Atlas (C1)', 'Kręg szczytowy (atlas) — pierwszy kręg szyjny, nie posiada trzonu. Tworzy staw szczytowo-potyliczny umożliwiający ruchy zgięcia i wyprostu głowy.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Axis (C2)', 'Kręg obrotowy (axis) — drugi kręg szyjny z zębem (dens axis), wokół którego obraca się atlas. Umożliwia rotację głowy.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vertebrae cervicales (C1-C7)', 'Kręgi szyjne — 7 kręgów odcinka szyjnego kręgosłupa. Charakterystyczne otwory wyrostków poprzecznych, przez które przechodzą tętnice kręgowe.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vertebrae thoracicae (Th1-Th12)', 'Kręgi piersiowe — 12 kręgów łączących się z żebrami. Posiadają dołki żebrowe na trzonach i wyrostkach poprzecznych. Tworzą tylną ścianę klatki piersiowej.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vertebrae lumbales (L1-L5)', 'Kręgi lędźwiowe — 5 największych kręgów. Przenoszą największe obciążenia. Najczęstsze miejsce przepuklin jądra miażdżystego (L4-L5, L5-S1).', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os sacrum', 'Kość krzyżowa — powstaje ze zrośnięcia 5 kręgów krzyżowych. Tworzy tylną ścianę miednicy. Łączy się ze stawami krzyżowo-biodrowymi.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os coccygis', 'Kość guziczna — szczątkowa kość z 3-5 zrośniętych kręgów guzicznych. Miejsce przyczepu mięśni dna miednicy i więzadła krzyżowo-guzicznego.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sternum', 'Mostek — płaska kość przedniej ściany klatki piersiowej. Składa się z rękojeści (manubrium), trzonu i wyrostka mieczykowatego. Miejsce punkcji szpiku.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Costae (I-XII)', 'Żebra — 12 par: 7 prawdziwych (I-VII), 3 rzekome (VIII-X) i 2 wolne (XI-XII). Chronią narządy klatki piersiowej i uczestniczą w oddychaniu.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Clavicula', 'Obojczyk — kość łącząca kończynę górną z tułowiem. Łączy się z mostkiem (staw mostkowo-obojczykowy) i wyrostkiem barkowym łopatki. Najczęściej łamana kość.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Scapula', 'Łopatka — płaska, trójkątna kość tylnej powierzchni klatki piersiowej. Posiada grzebień, wyrostek barkowy (acromion) i wyrostek kruczy (processus coracoideus).', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Humerus', 'Kość ramienna — długa kość ramienia. Głowa łączy się z łopatką (staw ramienno-łopatkowy). W rowku międzyguzkowym biegnie ścięgno głowy długiej bicepsa.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Radius', 'Kość promieniowa — leży po stronie kciuka przedramienia. Głowa tworzy staw z kością ramienną i łokciową. Dalszy koniec łączy się z kośćmi nadgarstka.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ulna', 'Kość łokciowa — leży po stronie małego palca. Wyrostek łokciowy (olecranon) tworzy szczyt łokcia. Wcięcie bloczkowe obejmuje bloczek kości ramiennej.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ossa carpi', 'Kości nadgarstka — 8 kości w dwóch rzędach. Bliższy: łódeczkowata, księżycowata, trójgraniasta, grochowata. Dalszy: czworoboczna większa i mniejsza, główkowata, haczykowata.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os scaphoideum', 'Kość łódeczkowata — najczęściej łamana kość nadgarstka. Złamania często niewidoczne na RTG. Zagrożenie martwicą z powodu wstecznego ukrwienia.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os lunatum', 'Kość księżycowata — centralna kość bliższego rzędu nadgarstka. Zwichnięcie może uciskać nerw pośrodkowy w kanale nadgarstka.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ossa metacarpi (I-V)', 'Kości śródręcza — 5 kości łączących nadgarstek z paliczkami. Złamanie V kości śródręcza (złamanie boksera) jest częstą urazową patologią.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Phalanges manus', 'Paliczki ręki — kciuk ma 2 paliczki (bliższy i dalszy), pozostałe palce po 3 (bliższy, środkowy, dalszy). Łącznie 14 paliczków w każdej ręce.', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os ilium', 'Kość biodrowa — największa część kości miednicznej. Talerz kości biodrowej jest miejscem pobierania szpiku do biopsji. Grzebień biodrowy jest punktem orientacyjnym.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os ischii', 'Kość kulszowa — dolno-tylna część kości miednicznej. Guz kulszowy (tuber ischiadicum) jest punktem podparcia przy siedzeniu i przyczepem mięśni kulszowo-goleniowych.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os pubis', 'Kość łonowa — przednio-dolna część kości miednicznej. Obie kości łonowe łączą się w spojeniu łonowym (symphysis pubica). Tworzy część panewki stawu biodrowego.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Acetabulum', 'Panewka stawu biodrowego — powstaje ze zrośnięcia trzech kości miedniczych (biodrowej, kulszowej, łonowej). Obejmuje głowę kości udowej.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Femur', 'Kość udowa — najdłuższa i najsilniejsza kość ciała. Głowa łączy się z panewką. Szyjka kości udowej jest częstym miejscem złamań u osób starszych (osteoporoza).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Patella', 'Rzepka — największa kość sezamoidalna. Leży w ścięgnie mięśnia czworogłowego uda. Chroni staw kolanowy i zwiększa ramię dźwigni wyprostu kolana.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tibia', 'Kość piszczelowa — większa kość goleni, przenosi obciążenie ciała. Plateau piszczelowe tworzy dolną powierzchnię stawu kolanowego. Guzowatość piszczeli to przyczep więzadła rzepki.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fibula', 'Kość strzałkowa — cienka kość boczna goleni. Nie przenosi obciążenia ciała. Kostka boczna stabilizuje staw skokowy. Nerw strzałkowy owija się wokół jej szyjki.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Talus', 'Kość skokowa — łączy się z piszczelą i strzałką tworząc staw skokowy górny. Nie ma przyczepów mięśniowych. Podatna na martwicę jałową po złamaniach.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Calcaneus', 'Kość piętowa — największa kość stopy. Przenosi siły przy chodzeniu. Przyczep ścięgna Achillesa. Złamania powstają przy upadku z wysokości.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ossa tarsi', 'Kości stępu — 7 kości: skokowa, piętowa, łódkowata, sześcienna i trzy klinowate. Tworzą łuki stopy przenoszące obciążenia.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ossa metatarsi (I-V)', 'Kości śródstopia — 5 kości między stępem a paliczkami. Złamanie zmęczeniowe II lub III kości śródstopia (złamanie marszowe) typowe u żołnierzy i biegaczy.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Phalanges pedis', 'Paliczki stopy — paluchy mają 2 paliczki, pozostałe palce po 3. Łącznie 14 paliczków. Paluch koślawy (hallux valgus) to częsta deformacja I paliczka.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os naviculare', 'Kość łódkowata stopy — leży po przyśrodkowej stronie stępu między kością skokową a klinowatymi. Guzek kości łódkowatej jest przyczepem mięśnia piszczelowego tylnego.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Os cuboideum', 'Kość sześcienna — leży po bocznej stronie stępu. Tworzy rowek dla ścięgna mięśnia strzałkowego długiego. Łączy się z piętową i IV-V kością śródstopia.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Ossa cuneiformia', 'Kości klinowate — trzy kości (przyśrodkowa, pośrednia, boczna) między kością łódkowatą a I-III kością śródstopia. Współtworzą sklepienie poprzeczne stopy.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Vertebra prominens (C7)', 'Kręg wyniosły — siódmy kręg szyjny o najdłuższym wyrostku kolczystym, wyczuwalny przy zgięciu szyi. Ważny punkt orientacyjny kliniczny.', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Foramen magnum', 'Otwór wielki kości potylicznej — przejście rdzenia przedłużonego w rdzeń kręgowy. Przechodzą przez niego także tętnice kręgowe i rdzeń przedłużony.', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fossa glenoidalis', 'Panewka stawowa łopatki — płytkie zagłębienie wyrostka barkowego łopatki. Tworzy staw ramienny. Obrąbek stawowy (labrum glenoidale) pogłębia panewkę.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Processus mastoideus', 'Wyrostek sutkowaty kości skroniowej — wyczuwalny za uchem. Zawiera komórki powietrzne. Przyczep mięśnia mostkowo-obojczykowo-sutkowego. Zapalenie = mastoiditis.', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Processus styloideus radii', 'Wyrostek rylcowaty kości promieniowej — wyczuwalny po stronie kciuka. Punkt orientacyjny do badania tętna na tętnicy promieniowej.', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Epicondylus lateralis humeri', 'Nadkłykieć boczny kości ramiennej — przyczep mięśni prostowników nadgarstka. Zapalenie przyczepów = łokieć tenisisty (epicondylitis lateralis).', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Epicondylus medialis humeri', 'Nadkłykieć przyśrodkowy kości ramiennej — przyczep mięśni zginaczy nadgarstka. Zapalenie przyczepów = łokieć golfisty. Za nadkłykciem biegnie nerw łokciowy.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Trochanter major', 'Krętarz większy kości udowej — duży guz na bocznej stronie bliższego końca kości udowej. Przyczep mięśni pośladkowych. Wyczuwalny przez skórę, punkt orientacyjny.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Malleolus medialis', 'Kostka przyśrodkowa — dolny koniec kości piszczelowej, wyczuwalny po wewnętrznej stronie stawu skokowego. Złamania kostek to najczęstsze złamania kończyny dolnej.', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Malleolus lateralis', 'Kostka boczna — dolny koniec kości strzałkowej, wyczuwalny po zewnętrznej stronie stawu skokowego. Stabilizuje staw skokowo-goleniowy bocznie.', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Musculus sternocleidomastoideus', 'Mięsień mostkowo-obojczykowo-sutkowy — przyczep: mostek i obojczyk → wyrostek sutkowaty. Jednostronny skurcz: przechylenie głowy w swoją stronę i obrót w przeciwną. Obustronny: zgięcie szyi.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus trapezius', 'Mięsień czworoboczny — rozciąga się od kości potylicznej i wyrostków kolczystych C1-Th12 do obojczyka, wyrostka barkowego i grzebienia łopatki. Unosi, zbliża i obraca łopatkę.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus deltoideus', 'Mięsień naramienny — przyczep: obojczyk, wyrostek barkowy, grzebień łopatki → guzowatość naramienna kości ramiennej. Odwodzi ramię. Dominujące miejsce iniekcji domięśniowych.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus pectoralis major', 'Mięsień piersiowy większy — przyczep: obojczyk, mostek, chrząstki żebrowe → grzebień guzka większego kości ramiennej. Przywiedzenie, zgięcie i rotacja wewnętrzna ramienia.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus latissimus dorsi', 'Mięsień najszerszy grzbietu — największy mięsień ciała. Przyczep: wyrostki kolczyste Th7-L5, powięź piersiowo-lędźwiowa → grzebień guzka mniejszego. Prostowanie, przywiedzenie i rotacja wewnętrzna ramienia.', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus biceps brachii', 'Mięsień dwugłowy ramienia — głowa długa: guzek nadpanewkowy łopatki, głowa krótka: wyrostek kruczy → guzowatość kości promieniowej. Zgięcie przedramienia i supinacja.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus triceps brachii', 'Mięsień trójgłowy ramienia — jedyny prostownik łokcia. Głowa długa: guzek podpanewkowy, głowa boczna i przyśrodkowa: kość ramienna → wyrostek łokciowy. Nerw promieniowy.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus brachioradialis', 'Mięsień ramienno-promieniowy — przyczep: grzebień nadkłykciowy boczny kości ramiennej → wyrostek rylcowaty kości promieniowej. Zgięcie przedramienia w pozycji pośredniej. Unerwienie: nerw promieniowy.', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus supraspinatus', 'Mięsień nadgrzebieniowy — od dołu nadgrzebieniowego łopatki → guzek większy kości ramiennej. Inicjuje odwodzenie ramienia (pierwsze 15°). Najczęściej uszkadzany mięsień stożka rotatorów.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus infraspinatus', 'Mięsień podgrzebieniowy — od dołu podgrzebieniowego łopatki → guzek większy kości ramiennej. Rotacja zewnętrzna ramienia. Drugi najczęściej uszkadzany mięsień stożka rotatorów.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus subscapularis', 'Mięsień podłopatkowy — od dołu podłopatkowego → guzek mniejszy kości ramiennej. Główny rotator wewnętrzny ramienia w stożku rotatorów.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus teres minor', 'Mięsień obły mniejszy — od bocznego brzegu łopatki → guzek większy kości ramiennej. Rotacja zewnętrzna ramienia. Element stożka rotatorów. Unerwienie: nerw pachowy.', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Diaphragma', 'Przepona — główny mięsień oddechowy, oddziela jamę klatki piersiowej od jamy brzusznej. Unerwiona przez nerw przeponowy (C3-C5). Posiada otwory dla aorty, żyły głównej dolnej i przełyku.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus rectus abdominis', 'Mięsień prosty brzucha — od wyrostka mieczykowatego i chrząstek żebrowych V-VII → spojenie łonowe. Zgięcie tułowia i tłocznia brzuszna. Przecinany przy laparotomii pośrodkowej.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus obliquus externus abdominis', 'Mięsień skośny zewnętrzny brzucha — od żeber V-XII → grzebień biodrowy i więzadło pachwinowe. Zgięcie i rotacja tułowia, tłocznia brzuszna. Rozcięgno tworzy kanał pachwinowy.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus obliquus internus abdominis', 'Mięsień skośny wewnętrzny brzucha — od powięzi piersiowo-lędźwiowej i grzebienia biodrowego → żebra X-XII i linia biała. Obraca tułów w swoją stronę. Tworzy mięsień dźwigacz jądra.', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus transversus abdominis', 'Mięsień poprzeczny brzucha — najgłębszy mięsień ściany brzucha. Stabilizacja kręgosłupa lędźwiowego i tłocznia brzuszna. Przyczep: chrząstki żebrowe VII-XII → linia biała.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus erector spinae', 'Mięsień prostownik grzbietu — grupa mięśni (biodrowo-żebrowy, najdłuższy, kolcowy) biegnąca wzdłuż kręgosłupa. Prostowanie i stabilizacja tułowia. Bóle lędźwiowe często związane z tym mięśniem.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus gluteus maximus', 'Mięsień pośladkowy wielki — największy i najsilniejszy mięsień ciała. Przyczep: kość biodrowa, krzyżowa → pasmo biodrowo-piszczelowe i guzowatość pośladkowa. Prostowanie i rotacja zewnętrzna biodra.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus gluteus medius', 'Mięsień pośladkowy średni — od zewnętrznej powierzchni kości biodrowej → krętarz większy. Odwodzenie biodra i stabilizacja miednicy w chodzie. Osłabienie = objaw Trendelenburga.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus gluteus minimus', 'Mięsień pośladkowy mały — od kości biodrowej → krętarz większy. Odwodzenie i rotacja wewnętrzna biodra. Współpracuje z m. pośladkowym średnim w stabilizacji miednicy.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus iliopsoas', 'Mięsień biodrowo-lędźwiowy — złożony z m. biodrowego i m. lędźwiowego większego. Najsilniejszy zginacz biodra. Przyczep: kręgi lędźwiowe i dół biodrowy → krętarz mniejszy kości udowej.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus piriformis', 'Mięsień gruszkowaty — od kości krzyżowej → krętarz większy. Rotacja zewnętrzna biodra. Nerw kulszowy biegnie pod nim lub przez niego — zespół mięśnia gruszkowatego może imitować rwę kulszową.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus quadriceps femoris', 'Mięsień czworogłowy uda — 4 głowy: prosty uda, obszerny boczny, przyśrodkowy i pośredni → rzepka → guzowatość piszczeli. Jedyny prostownik kolana. Unerwienie: nerw udowy.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus rectus femoris', 'Mięsień prosty uda — jedyna głowa m. czworogłowego przechodząca przez dwa stawy. Przyczep: kolec biodrowy przedni dolny → rzepka. Zgięcie biodra i wyprost kolana.', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus sartorius', 'Mięsień krawiecki — najdłuższy mięsień ciała. Od kolca biodrowego przedniego górnego → powierzchnia przyśrodkowa piszczeli (gęsia stopka). Zgięcie, odwodzenie i rotacja zewnętrzna biodra.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus adductor magnus', 'Mięsień przywodziciel wielki — największy mięsień grupy przywodzicieli. Przyczep: guz kulszowy i gałąź kości łonowej → kresa chropawa i guzek przywodzicieli. Przywiedzenie i prostowanie biodra.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus gracilis', 'Mięsień smukły — jedyny przywodziciel krzyżujący staw kolanowy. Od gałęzi dolnej kości łonowej → gęsia stopka piszczeli. Przywiedzenie biodra i zgięcie kolana.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus biceps femoris', 'Mięsień dwugłowy uda — głowa długa: guz kulszowy, głowa krótka: kresa chropawa → głowa strzałki. Zgięcie kolana i rotacja zewnętrzna goleni. Unerwienie: nerw kulszowy.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus semitendinosus', 'Mięsień półścięgnisty — od guza kulszowego → gęsia stopka piszczeli. Zgięcie kolana i rotacja wewnętrzna goleni. Ścięgno używane jako przeszczep w rekonstrukcji ACL.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus semimembranosus', 'Mięsień półbłoniasty — od guza kulszowego → kłykieć przyśrodkowy piszczeli. Zgięcie kolana i rotacja wewnętrzna goleni. Najgłębszy z mięśni kulszowo-goleniowych.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus gastrocnemius', 'Mięsień brzuchaty łydki — dwie głowy od kłykci kości udowej → ścięgno Achillesa → kość piętowa. Zgięcie podeszwowe stopy i zgięcie kolana. Najsilniejszy mięsień łydki.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus soleus', 'Mięsień płaszczkowaty — leży pod m. brzuchatym łydki. Od piszczeli i strzałki → ścięgno Achillesa. Zgięcie podeszwowe stopy. Ważny w utrzymaniu postawy stojącej (pompa żylna łydki).', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tendo calcaneus (Achillis)', 'Ścięgno Achillesa — najgrubsze i najsilniejsze ścięgno ciała. Łączy mięśnie łydki z kością piętową. Zerwanie typowe u sportowców 30-50 lat (nagły ból, test Thompsona dodatni).', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus tibialis anterior', 'Mięsień piszczelowy przedni — od piszczeli → kość klinowata przyśrodkowa i I kość śródstopia. Zgięcie grzbietowe stopy i supinacja. Porażenie = stopa opadająca (nerw strzałkowy głęboki).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus tibialis posterior', 'Mięsień piszczelowy tylny — najgłębszy mięsień tylnej grupy goleni. Od piszczeli, strzałki i błony międzykostnej → kość łódkowata i klinowate. Utrzymuje łuk przyśrodkowy stopy.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus peroneus longus', 'Mięsień strzałkowy długi — od głowy i trzonu strzałki → kość klinowata przyśrodkowa i I kość śródstopia (od strony podeszwy). Pronacja i zgięcie podeszwowe stopy. Podtrzymuje łuk poprzeczny.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus masseter', 'Mięsień żwacz — od łuku jarzmowego → gałąź i kąt żuchwy. Najsilniejszy mięsień żucia (podnoszenie żuchwy). Unerwienie: nerw żwaczowy z V3 (n. trójdzielny).', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus temporalis', 'Mięsień skroniowy — od dołu skroniowego → wyrostek dziobiasty żuchwy. Podnoszenie i cofanie żuchwy. Unerwienie: nerwy skroniowe głębokie z n. żuchwowego (V3).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus pterygoideus lateralis', 'Mięsień skrzydłowy boczny — jedyny mięsień otwierający usta (opuszczanie żuchwy). Przyczep: skrzydło większe kości klinowej → szyjka wyrostka kłykciowego. Wysuwanie żuchwy.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus orbicularis oculi', 'Mięsień okrężny oka — mięsień mimiczny otaczający oczodół. Zamyka powieki (mruganie, zaciskanie). Unerwienie: nerw twarzowy (VII). Porażenie = lagophthalmos (niezdolność zamknięcia oka).', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus orbicularis oris', 'Mięsień okrężny ust — mięsień mimiczny otaczający szparę ust. Zamykanie, zaciskanie ust i formowanie dźwięków mowy. Unerwienie: nerw twarzowy (VII).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus serratus anterior', 'Mięsień zębaty przedni — od żeber I-IX → brzeg przyśrodkowy łopatki. Odwodzenie i obrót łopatki, przyciskanie do klatki piersiowej. Porażenie (n. piersiowy długi) = łopatka skrzydlata.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus rhomboideus major', 'Mięsień równoległoboczny większy — od wyrostków kolczystych Th2-Th5 → brzeg przyśrodkowy łopatki. Przyciąga łopatkę do kręgosłupa i unosi ją. Unerwienie: nerw grzbietowy łopatki (C5).', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus levator scapulae', 'Mięsień dźwigacz łopatki — od wyrostków poprzecznych C1-C4 → kąt górny łopatki. Unosi łopatkę i przechyla szyjny odcinek kręgosłupa. Częsta przyczyna bólu karku.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus psoas major', 'Mięsień lędźwiowy większy — od trzonów i wyrostków poprzecznych Th12-L5 → krętarz mniejszy kości udowej. Silny zginacz biodra. Ropień m. lędźwiowego może towarzyszyć gruźlicy kręgosłupa.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus tensor fasciae latae', 'Mięsień napinacz powięzi szerokiej — od kolca biodrowego przedniego górnego → pasmo biodrowo-piszczelowe. Zgięcie, odwodzenie i rotacja wewnętrzna biodra. Stabilizacja kolana w wyproście.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculus popliteus', 'Mięsień podkolanowy — od kłykcia bocznego kości udowej → tylna powierzchnia piszczeli. Odryglowuje kolano z pełnego wyprostu (rotacja wewnętrzna piszczeli). Unerwienie: nerw piszczelowy.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculi intercostales externi', 'Mięśnie międzyżebrowe zewnętrzne — od dolnego brzegu żebra wyżej → górny brzeg żebra niżej. Unoszą żebra przy wdechu (mięśnie wdechowe). 11 par po każdej stronie.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Musculi intercostales interni', 'Mięśnie międzyżebrowe wewnętrzne — przebieg przeciwny do zewnętrznych. Obniżają żebra przy forsownym wydechu (mięśnie wydechowe). Aktywne przy kaszlu i kichaniu.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('Inhibitory ACE (ACEi)', 'Mechanizm: hamowanie konwertazy angiotensyny (ACE), zmniejszenie syntezy angiotensyny II. Przykłady: enalapril, ramipril, lisinopril. Wskazania: nadciśnienie, niewydolność serca, nefropatia cukrzycowa. DN: suchy kaszel, hiperkaliemia, obrzęk naczynioruchowy.', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Sartany (ARB)', 'Mechanizm: blokada receptora AT1 angiotensyny II. Przykłady: losartan, walsartan, telmisartan. Wskazania: nadciśnienie (alternatywa przy nietolerancji ACEi), niewydolność serca. DN: hiperkaliemia, hipotonia. Nie powodują kaszlu.', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Beta-adrenolityki (β-blokery)', 'Mechanizm: blokada receptorów β-adrenergicznych. Przykłady: metoprolol, bisoprolol (β1-selektywne), propranolol (nieselektywny). Wskazania: nadciśnienie, niewydolność serca, arytmie, po zawale. DN: bradykardia, bronchoskurcz, maskowanie hipoglikemii.', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Blokery kanału wapniowego — dihydropirydyny', 'Mechanizm: blokada kanałów Ca²⁺ typu L w mięśniach gładkich naczyń → rozszerzenie naczyń. Przykłady: amlodipina, nifedipina, felodipina. Wskazania: nadciśnienie, dławica. DN: obrzęki kostek, bóle głowy, zaczerwienienie twarzy.', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Blokery kanału wapniowego — niedihydropirydyny', 'Mechanizm: blokada kanałów Ca²⁺ w sercu i naczyniach → zmniejszenie częstości, kurczliwości i rozszerzenie naczyń. Przykłady: werapamil, diltiazem. Wskazania: arytmie nadkomorowe, dławica. DN: bradykardia, zaparcia (werapamil).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Diuretyki tiazydowe', 'Mechanizm: hamowanie kotransportera Na⁺/Cl⁻ w kanaliku dalszym. Przykłady: hydrochlorotiazyd, indapamid, chlortalidon. Wskazania: nadciśnienie, obrzęki. DN: hipokaliemia, hiperurykemia, hiperglikemia, hiponatremia.', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Diuretyki pętlowe', 'Mechanizm: hamowanie kotransportera Na⁺/K⁺/2Cl⁻ w ramieniu wstępującym pętli Henlego. Przykłady: furosemid, torasemid. Wskazania: obrzęk płuc, niewydolność serca, ostra niewydolność nerek. DN: hipokaliemia, ototoksyczność, odwodnienie.', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Diuretyki oszczędzające potas', 'Mechanizm: spironolakton — antagonista aldosteronu; amilorid — blokada kanału Na⁺ w kanaliku zbiorczym. Wskazania: niewydolność serca, hiperaldosteronizm, wodobrzusze. DN: hiperkaliemia, ginekomastia (spironolakton).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Statyny', 'Mechanizm: hamowanie reduktazy HMG-CoA → zmniejszenie syntezy cholesterolu w wątrobie, zwiększenie ekspresji receptorów LDL. Przykłady: atorwastatyna, rosuwastatyna, simwastatyna. DN: mialgia, rabdomioliza (rzadko), hepatotoksyczność.', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fibraty', 'Mechanizm: agoniści receptorów PPARα → zmniejszenie trójglicerydów, zwiększenie HDL. Przykłady: fenofibrat, gemfibrozyl. Wskazania: hipertriglicerydemia. DN: mialgia (zwiększone ryzyko z statynami), kamica żółciowa, hepatotoksyczność.', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Inhibitory pompy protonowej (IPP)', 'Mechanizm: nieodwracalne hamowanie H⁺/K⁺-ATPazy komórek okładzinowych żołądka. Przykłady: omeprazol, pantoprazol, esomeprazol. Wskazania: GERD, wrzody, eradykacja H. pylori. DN: hipoMg, złamania (długotrwale), zakażenia C. difficile.', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Antagoniści receptora H2', 'Mechanizm: blokada receptora histaminowego H2 w komórkach okładzinowych → zmniejszenie wydzielania HCl. Przykłady: ranitydyna (wycofana w wielu krajach), famotydyna. Wskazania: wrzody, GERD. DN: bóle głowy, rzadko ginekomastia (cymetydyna).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Metformina', 'Mechanizm: aktywacja AMPK, zmniejszenie glukoneogenezy wątrobowej, zwiększenie wrażliwości na insulinę. Lek I rzutu w cukrzycy typu 2. DN: biegunka, nudności, kwasica mleczanowa (rzadko). Przeciwwskazanie: ciężka niewydolność nerek.', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Pochodne sulfonylomocznika', 'Mechanizm: blokada kanałów K-ATP w komórkach β trzustki → wydzielanie insuliny. Przykłady: gliklazyd, glimepiryd, glipizyd. Wskazania: cukrzyca typu 2. DN: hipoglikemia, przyrost masy ciała. Wymagają czynnych komórek β.', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Inhibitory SGLT2 (flozyny)', 'Mechanizm: hamowanie kotransportera Na⁺/glukoza w kanaliku bliższym → glukozuria. Przykłady: empagliflozyna, dapagliflozyna, kanagliflozyna. Wskazania: cukrzyca t.2, niewydolność serca. DN: zakażenia dróg moczowych, kwasica ketonowa.', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Agoniści GLP-1', 'Mechanizm: naśladowanie inkretyny GLP-1 → stymulacja wydzielania insuliny, hamowanie glukagonu, opóźnienie opróżniania żołądka. Przykłady: liraglutyd, semaglutyd. DN: nudności, wymioty, zapalenie trzustki (rzadko).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Insulina — szybkodziałająca', 'Przykłady: lispro, aspart, glulizynowa. Początek: 10-15 min, szczyt: 1-2 h, czas: 3-5 h. Podawana przed posiłkami. Stosowana w pompach insulinowych i jako bolus w intensywnej insulinoterapii.', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Insulina — długodziałająca', 'Przykłady: glargina, detemir, degludek. Początek: 1-2 h, brak wyraźnego szczytu, czas: 20-42 h. Zapewnia stałe stężenie bazalne insuliny. DN: hipoglikemia (rzadziej niż NPH), lipodystrofia w miejscu wkłucia.', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Leki z grupy NLPZ', 'Mechanizm: hamowanie cyklooksygenazy (COX-1 i COX-2) → zmniejszenie syntezy prostaglandyn. Przykłady: ibuprofen, diklofenak, naproksen. Wskazania: ból, zapalenie, gorączka. DN: wrzody żołądka, nefrotoksyczność, ryzyko sercowo-naczyniowe.', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Selektywne inhibitory COX-2 (koksiby)', 'Mechanizm: wybiórcze hamowanie COX-2 → mniejsze ryzyko uszkodzenia żołądka. Przykłady: celekoksyb, etorikoksyb. Wskazania: OA, RZS. DN: zwiększone ryzyko sercowo-naczyniowe (zawał, udar). Rofekoksyb wycofany z rynku.', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Paracetamol (acetaminofen)', 'Mechanizm: hamowanie COX w OUN (dokładny mechanizm niejasny), brak działania przeciwzapalnego obwodowo. Wskazania: ból łagodny/umiarkowany, gorączka. DN: hepatotoksyczność przy przedawkowaniu (antidotum: N-acetylocysteina). Max 4 g/dobę.', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Opioidy — silne', 'Mechanizm: agonizm receptorów opioidowych μ → analgezja, euforia, depresja oddechowa. Przykłady: morfina, fentanyl, oksykodon. DN: zaparcia, nudności, sedacja, depresja oddechowa, uzależnienie. Antidotum: nalokson.', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tramadol', 'Mechanizm: słaby agonista receptora μ + hamowanie wychwytu zwrotnego serotoniny i noradrenaliny. Wskazania: ból umiarkowany/silny. DN: nudności, zawroty głowy, drgawki (obniża próg), ryzyko zespołu serotoninowego z SSRI.', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Penicyliny', 'Mechanizm: hamowanie syntezy ściany komórkowej bakterii (wiązanie z PBP). Przykłady: amoksycylina, ampicylina, penicylina G. Wskazania: szerokie spektrum infekcji. DN: reakcje alergiczne (do anafilaksji), biegunka. Oporność: β-laktamazy.', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Cefalosporyny', 'Mechanizm: hamowanie syntezy ściany komórkowej (jak penicyliny). Generacje I-V o coraz szerszym spektrum wobec Gram(-). Przykłady: cefaleksyna (I), cefuroksym (II), ceftriakson (III), cefepim (IV). DN: alergia krzyżowa z penicylinami (~2%).', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Makrolidy', 'Mechanizm: wiązanie z podjednostką 50S rybosomu → hamowanie syntezy białek bakterii. Przykłady: azytromycyna, klarytromycyna, erytromycyna. Wskazania: atypowe zapalenia płuc, H. pylori. DN: wydłużenie QT, zaburzenia żołądkowo-jelitowe.', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Fluorochinolony', 'Mechanizm: hamowanie gyrazy DNA (topoizomerazy II) i topoizomerazy IV bakterii. Przykłady: ciprofloksacyna, lewofloksacyna, moksyfloksacyna. DN: tendinopatia (zerwanie ścięgna Achillesa), neuropatia, wydłużenie QT, fotosensybilizacja.', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Aminoglikozydy', 'Mechanizm: wiązanie z podjednostką 30S rybosomu → błędne odczytywanie mRNA. Przykłady: gentamycyna, amikacyna, tobramycyna. Wskazania: ciężkie infekcje Gram(-), endocarditis. DN: nefrotoksyczność, ototoksyczność (nieodwracalna). Monitorowanie stężeń.', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tetracykliny', 'Mechanizm: wiązanie z podjednostką 30S → hamowanie przyłączania aminoacylo-tRNA. Przykłady: doksycyklina, tetracyklina, minocyklina. Wskazania: borelioza, trądzik, chlamydia. DN: fotosensybilizacja, przebarwienia zębów u dzieci, zaburzenia GI.', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Metronidazol', 'Mechanizm: tworzenie toksycznych metabolitów uszkadzających DNA w warunkach beztlenowych. Wskazania: zakażenia beztlenowe (Bacteroides, Clostridium), lamblioza, ameboza, H. pylori. DN: metaliczny smak, neuropatia, efekt disulfiramowy z alkoholem.', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wankomycyna', 'Mechanizm: hamowanie syntezy ściany komórkowej przez wiązanie z D-Ala-D-Ala peptydoglikanu. Wskazania: ciężkie infekcje MRSA, rzekomobłoniaste zapalenie jelit (doustnie). DN: zespół czerwonego człowieka (zbyt szybki wlew), nefrotoksyczność.', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Trimetoprim-sulfametoksazol (ko-trimoksazol)', 'Mechanizm: synergistyczne hamowanie syntezy kwasu foliowego — sulfametoksazol hamuje syntazę dihydropteroilową, trimetoprim reduktazę dihydrofolianową. Wskazania: ZUM, PCP (Pneumocystis). DN: wysypka, hiperkaliemia, supresja szpiku.', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Heparyna niefrakcjonowana (UFH)', 'Mechanizm: aktywacja antytrombiny III → hamowanie trombiny (IIa) i Xa. Podawanie: dożylne, monitorowanie aPTT. Wskazania: zakrzepica, zatorowość, terapia pomostowa. DN: krwawienia, małopłytkowość poheparynowa (HIT). Antidotum: protamina.', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Heparyny drobnocząsteczkowe (LMWH)', 'Mechanizm: głównie hamowanie czynnika Xa przez antytrombinę III. Przykłady: enoksaparyna, dalteparyna, nadroparyna. Podawanie: podskórne, bez rutynowego monitorowania. DN: krwawienia, HIT (rzadziej niż UFH).', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Warfaryna', 'Mechanizm: hamowanie reduktazy epoksydowej witaminy K → zmniejszenie syntezy czynników II, VII, IX, X. Monitorowanie: INR (cel 2-3). DN: krwawienia, teratogenność, martwica skóry. Liczne interakcje pokarmowe i lekowe.', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('DOAC — riwaroksaban, apiksaban', 'Mechanizm: bezpośrednie hamowanie czynnika Xa. Wskazania: profilaktyka udarów w AF, leczenie DVT/PE. DN: krwawienia. Antidotum: andeksanet alfa. Nie wymagają monitorowania INR. Ostrożnie w niewydolności nerek.', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Dabigatran', 'Mechanizm: bezpośredni inhibitor trombiny (czynnika IIa). Wskazania: profilaktyka udarów w AF, DVT/PE. DN: krwawienia, dyspepsja. Antidotum: idarucizumab. Wydalanie nerkowe — przeciwwskazany przy GFR <30 ml/min.', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Kwas acetylosalicylowy (aspiryna)', 'Mechanizm: nieodwracalne hamowanie COX-1 → zmniejszenie syntezy tromboksanu A2 → hamowanie agregacji płytek. Niskie dawki (75-100 mg): antyagregacyjne. DN: wrzody, krwawienia z GI, zespół Reye''a u dzieci.', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Klopidogrel', 'Mechanizm: nieodwracalna blokada receptora P2Y12 dla ADP na płytkach → hamowanie agregacji. Wskazania: po zawale, PCI ze stentem, udar. Podwójna terapia z ASA (DAPT). DN: krwawienia, TTP (rzadko). Prolek — wymaga aktywacji CYP2C19.', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('SSRI (selektywne inhibitory wychwytu serotoniny)', 'Mechanizm: hamowanie wychwytu zwrotnego serotoniny (5-HT) w synapsie. Przykłady: fluoksetyna, sertralina, escitalopram, paroksetyna. Wskazania: depresja, lęk, OCD, PTSD. DN: dysfunkcja seksualna, nudności, zespół serotoninowy.', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('SNRI (inhibitory wychwytu serotoniny i noradrenaliny)', 'Mechanizm: hamowanie wychwytu zwrotnego serotoniny i noradrenaliny. Przykłady: wenlafaksyna, duloksetyna. Wskazania: depresja, lęk uogólniony, ból neuropatyczny (duloksetyna). DN: nadciśnienie (wyższe dawki), nudności, zespół odstawienny.', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Benzodiazepiny', 'Mechanizm: nasilenie działania GABA na receptorze GABA-A (zwiększenie częstotliwości otwarcia kanału Cl⁻). Przykłady: diazepam, lorazepam, midazolam. Wskazania: lęk, bezsenność, drgawki, sedacja. DN: sedacja, uzależnienie, depresja oddechowa. Antidotum: flumazenil.', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Leki przeciwpadaczkowe — walproinian', 'Mechanizm: blokada kanałów Na⁺, zwiększenie GABA, hamowanie kanałów Ca²⁺ typu T. Szerokie spektrum: napady uogólnione i ogniskowe. DN: hepatotoksyczność, teratogenność (wady cewy nerwowej), przyrost masy ciała, trombocytopenia.', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Karbamazepina', 'Mechanizm: blokada kanałów Na⁺ zależnych od napięcia. Wskazania: padaczka (napady ogniskowe), neuralgia nerwu trójdzielnego, zaburzenie afektywne dwubiegunowe. DN: hiponatremia, agranulocytoza, zespół SJS/TEN, indukcja CYP3A4.', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Glikokortykosteroidy ogólnoustrojowe', 'Mechanizm: wiązanie z receptorem GR → hamowanie NF-κB → supresja cytokin zapalnych. Przykłady: prednizon, metyloprednizolon, deksametazon. Wskazania: stany zapalne, autoimmunologiczne, alergia. DN: osteoporoza, cukrzyca, zespół Cushinga.', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Leki antyhistaminowe H1 — II generacja', 'Mechanizm: blokada receptora H1 histaminy. Przykłady: cetyryzyna, loratadyna, feksofenadyna. Wskazania: alergiczny nieżyt nosa, pokrzywka. DN: minimalna sedacja (w przeciwieństwie do I generacji). Nie przenikają przez barierę krew-mózg.', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('β₂-mimetyki krótkodziałające (SABA)', 'Mechanizm: stymulacja receptorów β₂ w mięśniach gładkich oskrzeli → rozkurcz. Przykłady: salbutamol (albuterol), fenoterol. Wskazania: doraźne leczenie astmy i POChP. DN: tachykardia, drżenie rąk, hipokaliemia. Lek ratunkowy.', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Wziewne glikokortykosteroidy (ICS)', 'Mechanizm: miejscowe działanie przeciwzapalne w drogach oddechowych. Przykłady: budezonid, flutykazon, beklometazon. Wskazania: przewlekłe leczenie astmy (lek bazowy). DN: kandydoza jamy ustnej, chrypka. Płukanie ust po inhalacji.', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lewotyroksyna (L-T4)', 'Mechanizm: syntetyczny analog tyroksyny (T4), konwertowany do aktywnej T3 w tkankach. Wskazania: niedoczynność tarczycy. DN: przy przedawkowaniu objawy nadczynności (tachykardia, spadek masy, drżenia). Przyjmować na czczo, 30 min przed posiłkiem.', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Tiamazol (metimazol)', 'Mechanizm: hamowanie peroksydazy tarczycowej → zmniejszenie syntezy T3 i T4. Wskazania: nadczynność tarczycy (choroba Gravesa-Basedowa). DN: agranulocytoza (zagrożenie życia), hepatotoksyczność, wysypka. Kontrola morfologii krwi.', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
INSERT INTO flashcard_sets (user_id, name, description, tags, is_public, published_at, created_at, updated_at)
INSERT INTO flashcards (front, back, source, position, user_id, set_id, created_at, updated_at) VALUES
('-itis', 'Przyrostek oznaczający zapalenie. Przykłady: appendicitis (zapalenie wyrostka robaczkowego), arthritis (zapalenie stawu), meningitis (zapalenie opon mózgowo-rdzeniowych).', 'manual', 1, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-ectomia', 'Przyrostek oznaczający chirurgiczne usunięcie (wycięcie). Przykłady: appendectomia (wycięcie wyrostka), cholecystectomia (wycięcie pęcherzyka żółciowego), mastectomia (wycięcie piersi).', 'manual', 2, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-otomia', 'Przyrostek oznaczający nacięcie chirurgiczne (otwarcie). Przykłady: tracheotomia (nacięcie tchawicy), laparotomia (otwarcie jamy brzusznej), thoracotomia (otwarcie klatki piersiowej).', 'manual', 3, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-stomia', 'Przyrostek oznaczający wytworzenie sztucznego ujścia (przetoki). Przykłady: colostomia (przetoka jelita grubego), tracheostomia (przetoka tchawicy), gastrostomia (przetoka żołądkowa).', 'manual', 4, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-osis / -oza', 'Przyrostek oznaczający stan chorobowy (zwykle niezapalny) lub proces. Przykłady: fibrosis (włóknienie), stenosis (zwężenie), necrosis (martwica), thrombosis (zakrzepica).', 'manual', 5, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-penia', 'Przyrostek oznaczający niedobór, zmniejszenie liczby. Przykłady: leukopenia (niedobór leukocytów), thrombocytopenia (niedobór płytek), pancytopenia (niedobór wszystkich linii komórkowych).', 'manual', 6, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-emia', 'Przyrostek oznaczający stan we krwi. Przykłady: anemia (niedokrwistość), hyperglycemia (podwyższony cukier we krwi), septicemia (posocznica), hyperkaliemia (podwyższony potas we krwi).', 'manual', 7, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-uria', 'Przyrostek oznaczający obecność substancji w moczu. Przykłady: hematuria (krew w moczu), proteinuria (białko w moczu), glycosuria (glukoza w moczu), polyuria (wielomocz).', 'manual', 8, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-algia / -odynia', 'Przyrostek oznaczający ból. Przykłady: neuralgia (ból nerwowy), myalgia (ból mięśniowy), cephalalgia (ból głowy), pleurodynia (ból opłucnowy).', 'manual', 9, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-plastica', 'Przyrostek oznaczający naprawę chirurgiczną lub kształtowanie. Przykłady: rhinoplastica (plastyka nosa), angioplastica (plastyka naczynia), arthroplastica (plastyka stawu — endoproteza).', 'manual', 10, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-scopia', 'Przyrostek oznaczający oglądanie, badanie wzrokowe. Przykłady: endoscopia (wziernikowanie narządu), colonoscopia (wziernikowanie jelita grubego), bronchoscopia (wziernikowanie oskrzeli).', 'manual', 11, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-graphia', 'Przyrostek oznaczający zapis, rejestrację. Przykłady: electrocardiographia (EKG — zapis czynności serca), electromyographia (EMG — zapis mięśni), mammographia (rtg piersi).', 'manual', 12, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-megalia', 'Przyrostek oznaczający powiększenie. Przykłady: hepatomegalia (powiększenie wątroby), splenomegalia (powiększenie śledziony), cardiomegalia (powiększenie serca), acromegalia (powiększenie kończyn).', 'manual', 13, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-malacia', 'Przyrostek oznaczający rozmiękanie tkanki. Przykłady: osteomalacia (rozmiękanie kości), chondromalacia (rozmiękanie chrząstki), tracheomalacia (rozmiękanie tchawicy).', 'manual', 14, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-lysis', 'Przyrostek oznaczający rozpad, rozpuszczenie, zniszczenie. Przykłady: haemolysis (rozpad krwinek), thrombolysis (rozpuszczenie skrzepu), osteolysis (rozpad kości).', 'manual', 15, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-genesis / -genia', 'Przyrostek oznaczający powstawanie, tworzenie się. Przykłady: carcinogenesis (powstawanie raka), osteogenesis (tworzenie kości), pathogenesis (mechanizm powstawania choroby).', 'manual', 16, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-rrhaphia', 'Przyrostek oznaczający zszycie chirurgiczne. Przykłady: herniorrhaphia (zszycie przepukliny), neurorrhaphia (zszycie nerwu), tenorrhaphia (zszycie ścięgna).', 'manual', 17, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('-rrhagia / -rrhexis', 'Przyrostki oznaczające krwotok / pęknięcie. Przykłady: haemorrhagia (krwotok), menorrhagia (obfite miesiączki). -rrhexis: karyorrhexis (rozpad jądra komórkowego).', 'manual', 18, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('hyper-', 'Przedrostek oznaczający nadmiar, powyżej normy. Przykłady: hypertensio (nadciśnienie), hyperthyreoidismus (nadczynność tarczycy), hyperglycaemia (hiperglikemia).', 'manual', 19, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('hypo-', 'Przedrostek oznaczający niedobór, poniżej normy. Przykłady: hypotensio (niedociśnienie), hypothyreoidismus (niedoczynność tarczycy), hypoglycaemia (hipoglikemia).', 'manual', 20, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('tachy-', 'Przedrostek oznaczający szybki, przyspieszony. Przykłady: tachycardia (przyspieszone bicie serca >100/min), tachypnoea (przyspieszony oddech), tachyarrhythmia (szybka arytmia).', 'manual', 21, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('brady-', 'Przedrostek oznaczający wolny, zwolniony. Przykłady: bradycardia (zwolnione bicie serca <60/min), bradypnoea (zwolniony oddech), bradykinesia (spowolnienie ruchowe — choroba Parkinsona).', 'manual', 22, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('dys-', 'Przedrostek oznaczający zaburzenie, trudność, nieprawidłowość. Przykłady: dyspnoea (duszność), dysphagia (zaburzenie połykania), dysuria (bolesne oddawanie moczu), dysplasia (zaburzenie rozwoju).', 'manual', 23, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('a- / an-', 'Przedrostek oznaczający brak, bez. Przykłady: apnoea (bezdech), anuria (bezmocz), aphasia (utrata zdolności mowy), anaemia (niedokrwistość).', 'manual', 24, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('poly-', 'Przedrostek oznaczający wiele, dużo. Przykłady: polyuria (wielomocz), polydipsia (nadmierne pragnienie), polyneuropathia (uszkodzenie wielu nerwów), polycythaemia (nadmiar krwinek).', 'manual', 25, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('oligo-', 'Przedrostek oznaczający mało, niedostatecznie. Przykłady: oliguria (skąpomocz <500 ml/dobę), oligohydramnion (małowodzie), oligospermia (zmniejszona liczba plemników).', 'manual', 26, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('endo-', 'Przedrostek oznaczający wewnątrz. Przykłady: endocardium (wsierdzie), endoscopia (wziernikowanie wewnętrzne), endometrium (błona śluzowa macicy), endocrinologia (nauka o gruczołach dokrewnych).', 'manual', 27, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('ecto- / exo-', 'Przedrostki oznaczające na zewnątrz. Przykłady: ectopia (przemieszczenie poza normalne miejsce), exocrinologia (wydzielanie zewnętrzne), exostosis (narośl kostna na zewnątrz kości).', 'manual', 28, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('peri-', 'Przedrostek oznaczający wokół, dookoła. Przykłady: pericardium (osierdzie — worek otaczający serce), periosteum (okostna), peritoneum (otrzewna), perinatalny (wokół porodu).', 'manual', 29, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('epi-', 'Przedrostek oznaczający nad, powyżej, na powierzchni. Przykłady: epidermis (naskórek), epigastrium (nadbrzusze), epiduralis (nad oponą twardą), epiglottis (nagłośnia).', 'manual', 30, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('sub-', 'Przedrostek oznaczający pod, poniżej. Przykłady: subcutaneus (podskórny), sublingualis (podjęzykowy), subduralis (podtwardówkowy), subfebrilis (stan podgorączkowy).', 'manual', 31, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('inter-', 'Przedrostek oznaczający między. Przykłady: intercostalis (międzyżebrowy), intervertebralis (międzykręgowy), interstitialis (śródmiąższowy).', 'manual', 32, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('intra-', 'Przedrostek oznaczający wewnątrz, do wnętrza. Przykłady: intravenous (dożylny), intramuscular (domięśniowy), intracranialis (wewnątrzczaszkowy), intrathecalis (dooponowy).', 'manual', 33, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('retro-', 'Przedrostek oznaczający za, do tyłu. Przykłady: retroperitonealis (zaotrzewnowy), retroflexio (zagięcie do tyłu, np. macicy), retrobulbaris (za gałką oczną).', 'manual', 34, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('ante- / pre-', 'Przedrostki oznaczające przed (w czasie lub przestrzeni). Przykłady: antenatalis (przedporodowy), praeoperativus (przedoperacyjny), praeeclampsia (stan przedrzucawkowy).', 'manual', 35, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('post-', 'Przedrostek oznaczający po, za (w czasie). Przykłady: postoperativus (pooperacyjny), postpartum (po porodzie), post mortem (po śmierci — sekcja zwłok).', 'manual', 36, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('neo-', 'Przedrostek oznaczający nowy. Przykłady: neoplasma (nowotwór — nowy twór), neonatologia (nauka o noworodkach), neovascularisatio (tworzenie nowych naczyń).', 'manual', 37, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('cardio-', 'Rdzeń oznaczający serce. Przykłady: cardiologia (nauka o sercu), cardiomyopathia (choroba mięśnia sercowego), cardiopulmonalis (sercowo-płucny), tachycardia (przyspieszenie akcji serca).', 'manual', 38, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('hepato-', 'Rdzeń oznaczający wątrobę (gr. hepar). Przykłady: hepatitis (zapalenie wątroby), hepatomegalia (powiększenie wątroby), hepatocellularis (wątrobowokomórkowy), hepatotoxicus (uszkadzający wątrobę).', 'manual', 39, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('nephro- / ren-', 'Rdzeń oznaczający nerkę (gr. nephros / łac. ren). Przykłady: nephrologia (nefrologia), nephritis (zapalenie nerek), insufficientia renalis (niewydolność nerek), nephrotoxicus (nefrotoksyczny).', 'manual', 40, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('pneumo- / pulmo-', 'Rdzeń oznaczający płuco (gr. pneumon / łac. pulmo). Przykłady: pneumonia (zapalenie płuc), pneumothorax (odma opłucnowa), pulmonologia (nauka o płucach), embolismus pulmonalis (zatorowość płucna).', 'manual', 41, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('gastro-', 'Rdzeń oznaczający żołądek (gr. gaster). Przykłady: gastritis (zapalenie żołądka), gastrectomia (wycięcie żołądka), gastroscopia (wziernikowanie żołądka), gastroenterologia (nauka o chorobach GI).', 'manual', 42, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('entero-', 'Rdzeń oznaczający jelito (gr. enteron). Przykłady: enteritis (zapalenie jelita), enterococcus (paciorkowiec jelitowy), gastroenteritis (nieżyt żołądkowo-jelitowy), enteropathia (choroba jelita).', 'manual', 43, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('chole- / cholecysto-', 'Rdzeń oznaczający żółć / pęcherzyk żółciowy. Przykłady: cholecystitis (zapalenie pęcherzyka żółciowego), cholelithiasis (kamica żółciowa), cholangitis (zapalenie dróg żółciowych), cholestasis (zastój żółci).', 'manual', 44, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('haemo- / haemato-', 'Rdzeń oznaczający krew (gr. haima). Przykłady: haemorrhagia (krwotok), haematoma (krwiak), haematuria (krew w moczu), haematologia (nauka o chorobach krwi).', 'manual', 45, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('osteo-', 'Rdzeń oznaczający kość (gr. osteon). Przykłady: osteoporosis (zrzeszotnienie kości), osteomyelitis (zapalenie szpiku kostnego), osteoarthritis (choroba zwyrodnieniowa stawów), osteocyt (komórka kości).', 'manual', 46, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('myo-', 'Rdzeń oznaczający mięsień (gr. mys). Przykłady: myocardium (mięsień sercowy), myalgia (ból mięśniowy), myositis (zapalenie mięśni), myopathia (choroba mięśni).', 'manual', 47, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('neuro-', 'Rdzeń oznaczający nerw (gr. neuron). Przykłady: neurologia (nauka o chorobach układu nerwowego), neuropathia (uszkodzenie nerwu), neuralgia (ból nerwowy), neuritis (zapalenie nerwu).', 'manual', 48, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('dermo- / dermato-', 'Rdzeń oznaczający skórę (gr. derma). Przykłady: dermatologia (nauka o chorobach skóry), dermatitis (zapalenie skóry), epidermis (naskórek), dermatomyositis (zapalenie skórno-mięśniowe).', 'manual', 49, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('onco-', 'Rdzeń oznaczający guz, nowotwór (gr. onkos). Przykłady: oncologia (nauka o nowotworach), oncogenesis (powstawanie nowotworu), oncogene (gen nowotworowy).', 'manual', 50, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Lateralis / medialis', 'Lateralis — boczny (dalej od linii środkowej ciała). Medialis — przyśrodkowy (bliżej linii środkowej). Przykład: malleolus lateralis (kostka boczna) vs medialis (kostka przyśrodkowa).', 'manual', 51, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Proximalis / distalis', 'Proximalis — bliższy (bliżej tułowia lub początku struktury). Distalis — dalszy (dalej od tułowia). Przykład: phalanx proximalis (paliczek bliższy) vs distalis (dalszy).', 'manual', 52, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Anterior (ventralis) / posterior (dorsalis)', 'Anterior — przedni (ku przodowi ciała). Posterior — tylny (ku tyłowi). Ventralis = brzuszny. Dorsalis = grzbietowy. Przykład: mięśnie przednie (flexores) vs tylne (extensores) przedramienia.', 'manual', 53, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Superior / inferior', 'Superior — górny (bliżej głowy, cranialis). Inferior — dolny (bliżej stóp, caudalis). Przykład: vena cava superior (żyła główna górna) vs inferior (żyła główna dolna).', 'manual', 54, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Superficialis / profundus', 'Superficialis — powierzchowny (bliżej skóry). Profundus — głęboki (dalej od powierzchni). Przykład: arcus palmaris superficialis (łuk dłoniowy powierzchowny) vs profundus (głęboki).', 'manual', 55, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Supinatio / pronatio', 'Supinacja — obrót przedramienia tak, że dłoń zwraca się ku górze (jak trzymanie talerza zupy — supiny). Pronacja — dłoń zwraca się ku dołowi. Dotyczy też stopy (uniesienie/obniżenie brzegu przyśrodkowego).', 'manual', 56, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Abductio / adductio', 'Abductio — odwodzenie (oddalanie kończyny od linii środkowej ciała). Adductio — przywodzenie (przybliżanie do linii środkowej). Przykład: m. deltoideus odwodzi ramię, m. pectoralis major przywodzi.', 'manual', 57, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Flexio / extensio', 'Flexio — zgięcie (zmniejszenie kąta stawowego). Extensio — wyprost (zwiększenie kąta). Przykład: zgięcie łokcia (flexio) = skurcz bicepsa, wyprost (extensio) = skurcz tricepsa.', 'manual', 58, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Idiopathicus', 'Termin oznaczający chorobę o nieznanej przyczynie. Przykłady: fibrosis pulmonalis idiopathica (samoistne włóknienie płuc), thrombocytopenia idiopathica (ITP), scoliosis idiopathica.', 'manual', 59, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now()),
('Iatrogenicus', 'Termin oznaczający szkodę wywołaną działaniem medycznym (leczeniem, procedurą). Przykłady: zakażenie jatrogenne (po operacji), pneumothorax jatrogenny (po nakłuciu żyły podobojczykowej).', 'manual', 60, '00000000-0000-0000-0000-000000000001', v_set_id, now(), now());
